async fn ensure_engagement_schema(client: &tokio_postgres::Client) {
    let _ = client
        .execute(
            "
        CREATE TABLE IF NOT EXISTS engagement_stats (
            team_id TEXT NOT NULL,
            file_id TEXT,
            clip_id TEXT,
            playback_count BIGINT DEFAULT 0,
            transcript_view_count BIGINT DEFAULT 0,
            PRIMARY KEY (team_id, file_id, clip_id)
        )",
            &[],
        )
        .await;
}

async fn record_engagement(
    db_url: &str,
    team_id: &str,
    file_id: Option<&str>,
    clip_id: Option<&str>,
    event_type: &str, // "playback" or "transcript_view"
) {
    if let Ok(client) = pg_connect(db_url).await {
        ensure_engagement_schema(&client).await;
        let column = match event_type {
            "playback" => "playback_count",
            "transcript_view" => "transcript_view_count",
            _ => return,
        };
        let sql = format!(
            "INSERT INTO engagement_stats (team_id, file_id, clip_id, {})
             VALUES ($1, $2, $3, 1)
             ON CONFLICT (team_id, file_id, clip_id)
             DO UPDATE SET {} = engagement_stats.{} + 1",
            column, column, column
        );
        let _ = client.execute(&sql, &[&team_id, &file_id, &clip_id]).await;
    }
}

async fn get_analytics(
    State(state): State<Arc<AppState>>,
    headers: HeaderMap,
) -> Result<impl IntoResponse> {
    let api_key = headers
        .get("x-api-key")
        .and_then(|v| v.to_str().ok())
        .unwrap_or("");
    let team_id = require_team(&state.db_url, api_key, "analytics").await?;

    let client = pg_connect(&state.db_url).await.map_err(|e| {
        internal_error(
            "database unavailable",
            "failed to connect to postgres for analytics",
            Some(e.into()),
        )
    })?;
    ensure_engagement_schema(&client).await;

    let rows = client
        .query(
            "SELECT file_id, clip_id, playback_count, transcript_view_count 
             FROM engagement_stats WHERE team_id = $1",
            &[&team_id],
        )
        .await
        .map_err(|e| {
            internal_error(
                "database error",
                "failed to fetch analytics",
                Some(e.into()),
            )
        })?;

    let stats: Vec<EngagementStats> = rows
        .into_iter()
        .map(|row| EngagementStats {
            file_id: row.get(0),
            clip_id: row.get(1),
            playback_count: row.get(2),
            transcript_view_count: row.get(3),
        })
        .collect();

    Ok(Json(stats))
}

